import React, { useEffect, useState } from "react";
import {
  Box, Card, CardContent, Typography, Button, Grid,
  CircularProgress, Snackbar, Alert
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import { getRiderStatus, getRideHistory } from "../../services/api";
import { useAuth } from "../../contexts/AuthContext";
import SOSButton from "../../components/SOSButton";
import { io } from "socket.io-client";

const socket = io("http://localhost:5000");

export default function RiderDashboard() {
  const [rider, setRider] = useState(null);
  const [rides, setRides] = useState([]);
  const [pendingRides, setPendingRides] = useState([]);
  const [loading, setLoading] = useState(false);
  const [snackbar, setSnackbar] = useState({ open: false, message: "", type: "success" });

  const { auth, logout } = useAuth();
  const navigate = useNavigate();

  // ✅ Fetch rider data
  const fetchRiderData = async () => {
    try {
      setLoading(true);
      const res = await getRiderStatus();
      setRider(res.data.user || null);
    } catch {
      navigate("/rider-login");
    } finally {
      setLoading(false);
    }
  };

  // ✅ Fetch ride history
  const fetchRideHistory = async () => {
    try {
      const res = await getRideHistory();
      setRides(res.data.rides || []);
    } catch {
      setSnackbar({ open: true, message: "Failed to load ride history", type: "error" });
    }
  };

  // ✅ Fetch pending rides (initial)
  const fetchPendingRides = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/rides/pending", {
        headers: { Authorization: `Bearer ${auth?.token}` },
      });
      setPendingRides(res.data.rides || []);
    } catch {
      setSnackbar({ open: true, message: "Failed to fetch pending rides", type: "error" });
    }
  };

  // ✅ Accept ride
  const acceptRide = async (id) => {
    try {
      await axios.post(`http://localhost:5000/api/rides/${id}/accept`, {}, {
        headers: { Authorization: `Bearer ${auth?.token}` },
      });
      fetchPendingRides();
      fetchRideHistory();
    } catch {
      setSnackbar({ open: true, message: "Failed to accept ride", type: "error" });
    }
  };

  // ✅ Reject ride
  const rejectRide = async (id) => {
    try {
      await axios.post(`http://localhost:5000/api/rides/${id}/reject`, {}, {
        headers: { Authorization: `Bearer ${auth?.token}` },
      });
      fetchPendingRides();
    } catch {
      setSnackbar({ open: true, message: "Failed to reject ride", type: "error" });
    }
  };

  // ✅ Socket listeners
  useEffect(() => {
    fetchRiderData();
    fetchRideHistory();
    fetchPendingRides();

    socket.on("rideRequest", (ride) => {
      setPendingRides((prev) => [ride, ...prev]);
    });

    return () => socket.off("rideRequest");
  }, []);

  const handleLogout = () => {
    logout();
    navigate("/rider-login");
  };

  return (
    <Box p={4}>
      <Typography variant="h4" gutterBottom>Rider Dashboard</Typography>

      {loading ? (
        <CircularProgress />
      ) : rider ? (
        <Card sx={{ mb: 3, borderRadius: 3, boxShadow: 3 }}>
          <CardContent>
            <Typography variant="h6">{rider.fullName}</Typography>
            <Typography>Email: {rider.email}</Typography>
            <Typography>Mobile: {rider.mobile}</Typography>
            <Typography>
              Approval Status:{" "}
              <b style={{ color: rider.approvalStatus === "approved" ? "green" : "orange" }}>
                {rider.approvalStatus || "pending"}
              </b>
            </Typography>
            <Box mt={2}>
              <Button variant="contained" color="error" onClick={handleLogout}>Logout</Button>
            </Box>
          </CardContent>
        </Card>
      ) : (
        <Typography color="error">No rider data available</Typography>
      )}

      {/* 🚖 Pending Rides */}
      <Typography variant="h5" gutterBottom>Pending Ride Requests</Typography>
      <Grid container spacing={2}>
        {pendingRides.length === 0 ? (
          <Typography>No pending rides</Typography>
        ) : (
          pendingRides.map((ride) => (
            <Grid item xs={12} md={6} key={ride._id}>
              <Card sx={{ borderRadius: 3, boxShadow: 2 }}>
                <CardContent>
                  <Typography>Pickup: {ride.pickup}</Typography>
                  <Typography>Drop: {ride.drop}</Typography>
                  <Typography>Status: {ride.status}</Typography>
                  <Box mt={2} display="flex" gap={2}>
                    <Button variant="contained" color="success" onClick={() => acceptRide(ride._id)}>
                      Accept
                    </Button>
                    <Button variant="contained" color="error" onClick={() => rejectRide(ride._id)}>
                      Reject
                    </Button>
                  </Box>
                </CardContent>
              </Card>
            </Grid>
          ))
        )}
      </Grid>

      {/* 🚖 Ride History */}
      <Typography variant="h5" gutterBottom sx={{ mt: 4 }}>Ride History</Typography>
      <Grid container spacing={2}>
        {rides.length === 0 ? (
          <Typography>No rides found</Typography>
        ) : (
          rides.map((ride) => (
            <Grid item xs={12} md={6} key={ride._id}>
              <Card sx={{ borderRadius: 3, boxShadow: 2 }}>
                <CardContent>
                  <Typography>From: {ride.pickup}</Typography>
                  <Typography>To: {ride.drop}</Typography>
                  <Typography>Date: {new Date(ride.createdAt).toLocaleString()}</Typography>
                  <Typography>Status: {ride.status}</Typography>
                </CardContent>
              </Card>
            </Grid>
          ))
        )}
      </Grid>

      <Snackbar open={snackbar.open} autoHideDuration={3000}
        onClose={() => setSnackbar({ ...snackbar, open: false })}>
        <Alert severity={snackbar.type}>{snackbar.message}</Alert>
      </Snackbar>

      <SOSButton role="rider" />
    </Box>
  );
}
